### Step 2: Add or update code snippets

Create a new sample test file at `sdk/computefleet/Azure.ResourceManager.ComputeFleet/tests/Samples/SampleComputeFleet.cs`:

```csharp
// Copyright (c) Microsoft Corporation. All rights reserved.
// Licensed under the MIT License.

using System;
using System.Threading.Tasks;
using Azure.Identity;
using Azure.ResourceManager;
using Azure.ResourceManager.ComputeFleet;
using Azure.ResourceManager.ComputeFleet.Models;
using Azure.ResourceManager.Resources;
using NUnit.Framework;

namespace Azure.ResourceManager.ComputeFleet.Tests.Samples
{
    public class SampleComputeFleet : SamplesBase<ComputeFleetManagementTestEnvironment>
    {
        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task CreateFleet()
        {
            #region Snippet:ComputeFleet_CreateFleet
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription
                .GetResourceGroupAsync("<resource-group-name>");

            ComputeFleetCollection fleets = resourceGroup.GetComputeFleets();

            var fleetData = new ComputeFleetData(AzureLocation.EastUS)
            {
                Properties = new ComputeFleetProperties
                {
                    SpotPriorityProfile = new SpotPriorityProfile
                    {
                        Capacity = 20,
                        MinCapacity = 10,
                        MaxPricePerVM = -1,
                        EvictionPolicy = SpotEvictionPolicy.Delete,
                        AllocationStrategy = SpotAllocationStrategy.PriceCapacityOptimized,
                    },
                    OnDemandCapacityReservationProfile = new OnDemandCapacityReservationProfile
                    {
                        CapacityReservationGroupId = null,
                    },
                    ComputeProfile = new ComputeFleetComputeProfile(
                        new System.Collections.Generic.List<ComputeFleetVmProfile>
                        {
                            new ComputeFleetVmProfile
                            {
                                VmSize = "Standard_D2s_v3",
                                Count = 5,
                            },
                        }),
                },
            };

            ArmOperation<ComputeFleetResource> operation = await fleets.CreateOrUpdateAsync(
                WaitUntil.Completed, "<fleet-name>", fleetData);
            ComputeFleetResource fleet = operation.Value;
            Console.WriteLine($"Fleet created: {fleet.Id}");
            #endregion
        }

        [Test]
        [SyncOnly]
        [Ignore("Only verifying that the sample builds")]
        public async Task ListFleets()
        {
            #region Snippet:ComputeFleet_ListFleets
            ArmClient client = new ArmClient(new DefaultAzureCredential());
            SubscriptionResource subscription = await client.GetDefaultSubscriptionAsync();
            ResourceGroupResource resourceGroup = await subscription
                .GetResourceGroupAsync("<resource-group-name>");

            await foreach (ComputeFleetResource fleet in resourceGroup.GetComputeFleets())
            {
                Console.WriteLine($"Fleet: {fleet.Data.Name} in {fleet.Data.Location}");
            }
            #endregion
        }
    }
}
```

For each snippet:
- `ComputeFleet_CreateFleet` — maps to the `#region Snippet:ComputeFleet_CreateFleet` block above; add placeholder in README under "### Create a Compute Fleet"
- `ComputeFleet_ListFleets` — maps to the `#region Snippet:ComputeFleet_ListFleets` block above; add placeholder in README under "### List Compute Fleets in a resource group"

> **Note:** Adjust the exact model constructor signatures to match the generated types in `sdk/computefleet/Azure.ResourceManager.ComputeFleet/src/Generated/`. Check the `ComputeFleetData`, `ComputeFleetProperties`, `SpotPriorityProfile`, and `ComputeFleetComputeProfile` types before finalizing the sample.

